export function isLocale(value) {
  return LOCALES.includes(value);
}

export function localeFromPath(pathname = "/") {
  const first = pathname.split("/").filter(Boolean)[0];
  return LOCALIZED_LOCALES.includes(first) ? first : "en";
}

export function stripLocale(pathname = "/") {
  const parts = pathname.split("/").filter(Boolean);
  if (LOCALIZED_LOCALES.includes(parts[0])) parts.shift();
  return parts.length ? `/${parts.join("/")}` : "/";
}

export function localizePath(pathname = "/", locale = "en") {
  const clean = stripLocale(pathname);
  if (locale === "en") return clean;
  return clean === "/" ? `/${locale}` : `/${locale}${clean}`;
}

export function languageAlternates(pathname = "/", locale = "en") {
  const languages = Object.fromEntries(LOCALES.map((code) => [code, localizePath(pathname, code)]));
  languages["x-default"] = localizePath(pathname, "en");
  return { canonical: localizePath(pathname, locale), languages };
}

export function absoluteLocalizedUrl(pathname = "/", locale = "en") {
  return `${SITE_URL}${localizePath(pathname, locale)}`;
}

export function getCopy(locale = "en") {
  return COPY[locale] || COPY.en;
}

export function localizeCategories(categories, locale = "en") {
  const translations = categoryCopy[locale] || categoryCopy.en;
  return categories.map((category) => {
    const translated = translations[category.slug] || categoryCopy.en[category.slug];
    return { ...category, name: translated[0], eyebrow: translated[1], description: translated[2] };
  });
}

export function localizeGuides(guides, locale = "en") {
  const translations = guideCopy[locale] || guideCopy.en;
  return guides.map((guide) => {
    const translated = translations[guide.slug] || guideCopy.en[guide.slug];
    return { ...guide, title: translated[0], short: translated[1] };
  });
}
